package org.eclipse.rdf4j.common.transaction;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import org.junit.jupiter.api.Test;

class JoinReadAheadDepthFactoryTest {

	private final JoinReadAheadDepthFactory factory = new JoinReadAheadDepthFactory();

	@Test
	void parsesPositiveDepth() {
		var parsed = factory.getTransactionSetting("7");
		assertTrue(parsed.isPresent());
		assertEquals(JoinReadAheadDepth.of(7), parsed.get());
	}

	@Test
	void parsesZeroDepth() {
		var parsed = factory.getTransactionSetting("0");
		assertTrue(parsed.isPresent());
		assertEquals(JoinReadAheadDepth.of(0), parsed.get());
	}

	@Test
	void rejectsNegativeDepth() {
		var parsed = factory.getTransactionSetting("-1");
		assertTrue(parsed.isEmpty());
	}

	@Test
	void registryExposesFactory() {
		var maybeFactory = TransactionSettingRegistry.getInstance().get(JoinReadAheadDepth.NAME);
		assertTrue(maybeFactory.isPresent());
		var parsed = maybeFactory.get().getTransactionSetting("3");
		assertTrue(parsed.isPresent());
		assertEquals(JoinReadAheadDepth.of(3), parsed.get());
	}
}
